function drawArrow(ctx: CanvasRenderingContext2D, points: Point[], style: any) {
  if (points.length < 2) return;

  const start = points[0];
  const end = points[1];

  // Draw line
  ctx.beginPath();
  ctx.moveTo(start.x, start.y);
  ctx.lineTo(end.x, end.y);
  ctx.stroke();

  // Draw arrowhead
  const angle = Math.atan2(end.y - start.y, end.x - start.x);
  const headLen = 15;

  ctx.beginPath();
  ctx.moveTo(end.x, end.y);
  ctx.lineTo(
    end.x - headLen * Math.cos(angle - Math.PI / 6),
    end.y - headLen * Math.sin(angle - Math.PI / 6)
  );
  ctx.moveTo(end.x, end.y);
  ctx.lineTo(
    end.x - headLen * Math.cos(angle + Math.PI / 6),
    end.y - headLen * Math.sin(angle + Math.PI / 6)
  );
  ctx.stroke();
}

function drawText(ctx: CanvasRenderingContext2D, point: Point, text: string, style: any) {
  ctx.fillStyle = style.color || '#ffffff';
  ctx.font = `${style.fontSize || 14}px sans-serif`;
  ctx.textAlign = 'left';

  // Draw background
  const metrics = ctx.measureText(text);
  ctx.fillStyle = 'rgba(0,0,0,0.7)';
  ctx.fillRect(
    point.x - 2, 
    point.y - (style.fontSize || 14) - 2, 
    metrics.width + 4, 
    (style.fontSize || 14) + 4
  );

  ctx.fillStyle = style.color || '#ffffff';
  ctx.fillText(text, point.x, point.y);
}

function drawFreehand(ctx: CanvasRenderingContext2D, points: Point[], style: any) {
  if (points.length < 2) return;

  ctx.beginPath();
  ctx.moveTo(points[0].x, points[0].y);

  for (let i = 1; i < points.length; i++) {
    ctx.lineTo(points[i].x, points[i].y);
